 20	import { store } from 'store/ConfigStore';
 21	import { TimeInMilliseconds } from '../../types/Common';
 22	import { ServiceDetailsInfo } from '../../types/ServiceInfo';
 23	import { KialiAppState } from '../../store/Store';
 24	import { Graph } from './Graph';
 25	import { WizardAction, WizardMode } from 'components/IstioWizards/WizardActions';
 26	import { isKiosk, isParentKiosk, kioskContextMenuAction } from 'components/Kiosk/KioskActions';
 27	import { ServiceWizardActionsDropdownGroup } from 'components/IstioWizards/ServiceWizardActionsDropdownGroup';
 28	import { toRangeString } from 'components/Time/Utils';
 29	import { KioskElement } from 'components/Kiosk/KioskElement';
 30	import { TimeDurationIndicator } from 'components/Time/TimeDurationIndicator';
 31	import { TimeDurationModal } from 'components/Time/TimeDurationModal';
 32	import { KialiDispatch } from 'types/Redux';
 33	import { bindActionCreators } from 'redux';
 34	import { GraphActions } from 'actions/GraphActions';
 35	import { NodeData } from './GraphElems';
 36	import { elems, selectAnd } from 'helpers/GraphHelpers';
 37	import { KialiIcon } from 'config/KialiIcon';
 38	import { kebabToggleStyle } from 'styles/DropdownStyles';
 39	import { WorkloadWizardActionsDropdownGroup } from 'components/IstioWizards/WorkloadWizardActionsDropdownGroup';
 40	import { Workload } from 'types/Workload';
 41	import { GraphRefs } from './GraphPage';
 42	import { EmptyGraphLayout } from 'pages/Graph/EmptyGraphLayout';
 43	
 44	type ReduxDispatchProps = {
 45	  setEdgeMode: (edgeMode: EdgeMode) => void;
 46	  setLayout: (layout: GraphLayout) => void;
 47	  setUpdateTime: (val: TimeInMilliseconds) => void;
 48	  updateSummary: (summaryData: SummaryData) => void;
 49	};
 50	
 51	type ReduxProps = ReduxDispatchProps & {
 52	  kiosk: string;
 53	};
 54	
 55	type MiniGraphCardProps = ReduxProps & {
 56	  dataSource: GraphDataSource;
 57	  namespace?: string;
 58	  onDeleteTrafficRouting?: (key: string) => void;
 59	  onLaunchWizard?: (key: WizardAction, mode: WizardMode) => void;
 60	  refreshWorkload?: () => void;
 61	  serviceDetails?: ServiceDetailsInfo | null;
 62	  workload?: Workload | null;
 63	};
 64	
 65	type MiniGraphCardState = {
 66	  graphData: DecoratedGraphElements;
 67	  graphRefs?: GraphRefs;
 68	  isKebabOpen: boolean;
 69	  isLoading: boolean;
 70	  isReady: boolean;
 71	  isTimeOptionsOpen: boolean;
 72	};
 73	
 74	class MiniGraphCardComponent extends React.Component<MiniGraphCardProps, MiniGraphCardState> {
 75	  constructor(props: MiniGraphCardProps) {
 76	    super(props);
 77	    this.state = {
 78	      isKebabOpen: false,
 79	      isLoading: props.dataSource.isLoading,
 80	      isReady: false,
 81	      isTimeOptionsOpen: false,
 82	      graphData: props.dataSource.graphData
 83	    };
 84	  }
 85	
 86	  componentDidMount(): void {
 87	    this.props.dataSource.on('fetchSuccess', this.refresh);
 88	    this.props.dataSource.on('fetchError', this.refresh);
 89	  }
 90	
 91	  componentWillUnmount(): void {
 92	    this.props.dataSource.removeListener('fetchSuccess', this.refresh);
 93	    this.props.dataSource.removeListener('fetchError', this.refresh);
 94	  }
 95	
 96	  private refresh = (): void => {
 97	    this.setState({ graphData: this.props.dataSource.graphData, isLoading: this.props.dataSource.isLoading });
 98	  };
 99	
100	  render(): React.ReactNode {
101	    const graphCardActions = [
102	      <DropdownItem key="viewFullGraph" onClick={this.onViewFullGraph}>
103	        Show full graph
104	      </DropdownItem>,
105	      <DropdownItem key="viewNodeGraph" onClick={this.onViewNodeGraph}>
106	        Show node graph
107	      </DropdownItem>
108	    ];
109	
110	    if (isKiosk(this.props.kiosk)) {
111	      if (this.props.workload && this.props.namespace) {
112	        graphCardActions.push(
113	          <WorkloadWizardActionsDropdownGroup
114	            actionsLabel={true}
115	            namespace={this.props.namespace}
116	            onAction={this.handleWorkloadAction}
117	            workload={this.props.workload}
118	          ></WorkloadWizardActionsDropdownGroup>
119	        );
120	      } else if (this.props.serviceDetails) {
121	        graphCardActions.push(
122	          <ServiceWizardActionsDropdownGroup
123	            virtualServices={this.props.serviceDetails.virtualServices ?? []}
124	            destinationRules={this.props.serviceDetails.destinationRules ?? []}
125	            k8sGRPCRoutes={this.props.serviceDetails.k8sGRPCRoutes ?? []}
126	            k8sHTTPRoutes={this.props.serviceDetails.k8sHTTPRoutes ?? []}
127	            istioPermissions={this.props.serviceDetails.istioPermissions}
128	            onAction={this.handleLaunchWizard}
129	            onDelete={this.handleDeleteTrafficRouting}
130	          />
131	        );
132	      }
133	    }
134	
135	    // The parent component supplies the datasource and the target element. Here we protect against a lifecycle issue where the two
136	    // can be out of sync. If so, just assume the parent is currently loading until things get synchronized.
137	    const isLoading =
138	      (this.props.workload && this.props.workload?.name !== this.props.dataSource.fetchParameters.node?.workload) ||
139	      (this.props.serviceDetails &&
140	        this.props.serviceDetails?.service.name !== this.props.dataSource.fetchParameters.node?.service)
141	        ? true
142	        : this.props.dataSource.isLoading;
143	
144	    const rangeEnd: TimeInMilliseconds = this.props.dataSource.graphTimestamp * 1000;
145	    const rangeStart: TimeInMilliseconds = rangeEnd - this.props.dataSource.graphDuration * 1000;
146	
147	    const intervalTitle =
148	      rangeEnd > 0 ? toRangeString(rangeStart, rangeEnd, { second: '2-digit' }, { second: '2-digit' }) : 'Loading';
149	
150	    return (
151	      <>
152	        <Card style={{ height: '100%' }} id={'MiniGraphCard'} data-test="mini-graph">
153	          <CardHeader
154	            actions={{
155	              actions: (
156	                <>
157	                  <KioskElement>
158	                    <ToolbarItem>
159	                      <TimeDurationIndicator onClick={this.toggleTimeOptionsVisibility} isDuration={true} />
160	                    </ToolbarItem>
161	                  </KioskElement>
162	                  <Dropdown
163	                    toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
164	                      <MenuToggle
165	                        id="minigraph-toggle"
166	                        ref={toggleRef}
167	                        className={kebabToggleStyle}
168	                        aria-label="Actions"
169	                        variant="plain"
170	                        onClick={() => this.onGraphActionsToggle(!this.state.isKebabOpen)}
171	                        isExpanded={this.state.isKebabOpen}
172	                      >
173	                        <KialiIcon.KebabToggle />
174	                      </MenuToggle>
175	                    )}
176	                    isOpen={this.state.isKebabOpen}
177	                    onOpenChange={(isOpen: boolean) => this.onGraphActionsToggle(isOpen)}
178	                    popperProps={{ position: 'right' }}
179	                  >
180	                    <DropdownList>{graphCardActions}</DropdownList>
181	                  </Dropdown>
182	                </>
183	              ),
184	              hasNoOffset: false,
185	              className: undefined
186	            }}
187	          >
188	            <CardTitle style={{ float: 'left' }}>{intervalTitle}</CardTitle>
189	          </CardHeader>
190	
191	          <CardBody>
192	            <div id="pft-graph" style={{ height: '100%' }}>
193	              <EmptyGraphLayout
194	                elements={this.state.graphData}
195	                isLoading={isLoading}
196	                isError={this.props.dataSource.isError}
197	                isMiniGraph={true}
198	                loaded={true}
199	              >
200	                <Graph
201	                  edgeLabels={this.props.dataSource.fetchParameters.edgeLabels}
202	                  edgeMode={EdgeMode.ALL}
203	                  graphData={{
204	                    elements: this.state.graphData,
205	                    elementsChanged: true,
206	                    errorMessage: !!this.props.dataSource.errorMessage ? this.props.dataSource.errorMessage : undefined,
207	                    isError: this.props.dataSource.isError,
208	                    isLoading: isLoading,
209	                    loaded: true,
210	                    fetchParams: this.props.dataSource.fetchParameters,
211	                    timestamp: this.props.dataSource.graphTimestamp
212	                  }}
213	                  isMiniGraph={true}
214	                  layout={GraphLayout.Dagre}
215	                  onDeleteTrafficRouting={this.handleDeleteTrafficRouting}
216	                  onEdgeTap={this.handleEdgeTap}
217	                  onLaunchWizard={this.handleLaunchWizard}
218	                  onNodeTap={this.handleNodeTap}
219	                  onReady={this.handleReady}
220	                  rankBy={[]}
221	                  setEdgeMode={this.props.setEdgeMode}
222	                  setLayout={this.props.setLayout}
223	                  setRankResult={() => {}}
224	                  setUpdateTime={this.props.setUpdateTime}
225	                  updateSummary={this.props.updateSummary}
226	                  showLegend={false}
227	                  showRank={false}
228	                  showOutOfMesh={true}
229	                  showSecurity={true}
230	                  showTrafficAnimation={false}
231	                  showVirtualServices={true}
232	                />
233	              </EmptyGraphLayout>
234	            </div>
235	          </CardBody>
236	        </Card>
237	
238	        <TimeDurationModal
239	          customDuration={false}
240	          isOpen={this.state.isTimeOptionsOpen}
241	          onConfirm={this.toggleTimeOptionsVisibility}
242	          onCancel={this.toggleTimeOptionsVisibility}
243	        />
244	      </>
245	    );
246	  }
247	
248	  private handleReady = (refs: GraphRefs): void => {
249	    this.setState({ graphRefs: refs, isReady: true });
250	  };
251	
252	  private handleLaunchWizard = (key: WizardAction, mode: WizardMode): void => {
253	    this.onGraphActionsToggle(false);
254	    if (this.props.onLaunchWizard) {
255	      this.props.onLaunchWizard(key, mode);
256	    }
257	  };
258	
259	  private handleDeleteTrafficRouting = (key: string): void => {
260	    this.onGraphActionsToggle(false);
261	    if (this.props.onDeleteTrafficRouting) {
262	      this.props.onDeleteTrafficRouting(key);
263	    }
264	  };
265	
266	  private handleWorkloadAction = (): void => {
267	    this.onGraphActionsToggle(false);
268	    if (this.props.refreshWorkload) {
269	      this.props.refreshWorkload();
270	    }
271	  };
272	
273	  private handleEdgeTap = (edge: Edge<EdgeModel>): void => {
274	    const source = edge.getSource();
275	    const sourceData = source.getData() as NodeData;
276	    const target = edge.getTarget();
277	    const targetData = target.getData() as NodeData;
278	
279	    const selected = selectAnd(elems(source.getController()).nodes, [{ prop: 'isSelected', op: 'truthy' }]);
280	
281	    if (selected.length === 0) {
282	      return;
283	    }
284	
285	    const nodeData = selected[0].getData();
286	    const nodeApp = nodeData.app;
287	    const nodeService = nodeData.service;
288	    const nodeType = nodeData.nodeType;
289	
290	    if (source.getId() !== target.getId()) {
291	      const urlParams = new URLSearchParams(location.getSearch());
292	
293	      switch (nodeType) {
294	        case NodeType.APP: {
295	          const isInbound = targetData.app === nodeApp;
296	          const destination = isInbound ? 'source_canonical_service' : 'destination_canonical_service';
297	          urlParams.set('tab', isInbound ? 'in_metrics' : 'out_metrics');
298	          urlParams.set(URLParam.BY_LABELS, `${destination}=${isInbound ? sourceData.app : targetData.app}`);
299	          break;
300	        }
301	        case NodeType.SERVICE: {
302	          const isInbound = targetData.service === nodeService;
303	          const destination = isInbound ? 'source_canonical_service' : 'destination_canonical_service';
304	          urlParams.set('tab', 'metrics');
305	          urlParams.set(URLParam.BY_LABELS, `${destination}=${isInbound ? sourceData.app : targetData.app}`);
306	          break;
307	        }
308	        case NodeType.WORKLOAD: {
309	          const isInbound = targetData.app === nodeApp;
310	          const destination = isInbound ? 'source_canonical_service' : 'destination_canonical_service';
311	          urlParams.set('tab', isInbound ? 'in_metrics' : 'out_metrics');
312	          urlParams.set(URLParam.BY_LABELS, `${destination}=${isInbound ? sourceData.app : targetData.app}`);
313	        }
314	      }
315	
316	      router.navigate(`${location.getPathname()}?&{urlParams.toString()}`, { replace: true });
317	    }
318	  };
319	
320	  private handleNodeTap = (node: Node<NodeModel>): void => {
321	    const data = node.getData() as NodeData;
322	
323	    // Do nothing on inaccessible nodes or service entry nodes
324	    if (data.isInaccessible || data.isServiceEntry) {
325	      return;
326	    }
327	
328	    // If we are already on the details page of the tapped node, do nothing.
329	    const displayedNode = this.props.dataSource.fetchParameters.node!;
330	
331	    // Minigraph will consider box nodes as app
332	    const eNodeType = data.nodeType === 'box' && data.isBox ? data.isBox : data.workload ? 'workload' : data.nodeType;
333	
334	    const isSameResource =
335	      displayedNode.namespace.name === data.namespace &&
336	      displayedNode.nodeType === eNodeType &&
337	      displayedNode[displayedNode.nodeType] === data[eNodeType];
338	
339	    if (isSameResource) {
340	      return;
341	    }
342	
343	    // unselect the currently selected node
344	    (node as any).selected = false;
345	
346	    // Redirect to the details page of the tapped node.
347	    let resource = data[eNodeType];
348	    let resourceType: string = eNodeType === NodeType.APP ? 'application' : eNodeType;
349	
350	    let href = `/namespaces/${data.namespace}/${resourceType}s/${resource}`;
351	
352	    if (data.cluster) {
353	      href = `${href}?clusterName=${data.cluster}`;
354	    }
355	
356	    if (isParentKiosk(this.props.kiosk)) {
357	      kioskContextMenuAction(href);
358	    } else {
359	      router.navigate(href);
360	    }
361	  };
362	
363	  private onGraphActionsToggle = (isOpen: boolean): void => {
364	    this.setState({
365	      isKebabOpen: isOpen
366	    });
367	  };
368	
369	  private onViewFullGraph = (): void => {
370	    const namespace = this.props.dataSource.fetchParameters.namespaces[0].name;
371	    let graphType: GraphType = GraphType.APP;
372	
373	    const selected = selectAnd(elems(this.state.graphRefs!.getController()).nodes, [
374	      { prop: 'isSelected', op: 'truthy' }
375	    ]);
376	    const focusSelector = selected.length > 0 ? `${URLParam.FOCUS_SELECTOR}=${encodeURI(selected[0].getId())}` : '';
377	
378	    const graphUrl = `/graph/namespaces?graphType=${graphType}&injectServiceNodes=true&namespaces=${namespace}&${focusSelector}`;
379	
380	    if (isParentKiosk(this.props.kiosk)) {
381	      kioskContextMenuAction(graphUrl);
382	    } else {
383	      router.navigate(graphUrl);
384	    }
385	  };
386	
387	  private onViewNodeGraph = (): void => {
388	    let graphType = this.props.dataSource.fetchParameters.graphType;
389	
390	    switch (this.props.dataSource.fetchParameters.node!.nodeType) {
391	      case NodeType.APP:
392	        graphType = GraphType.APP;
393	        break;
394	      case NodeType.SERVICE:
395	        graphType = GraphType.SERVICE;
396	        break;
397	      case NodeType.WORKLOAD:
398	        graphType = GraphType.WORKLOAD;
399	        break;
400	    }
401	
402	    const urlParams: GraphUrlParams = {
403	      activeNamespaces: this.props.dataSource.fetchParameters.namespaces,
404	      duration: this.props.dataSource.fetchParameters.duration,
405	      edgeLabels: this.props.dataSource.fetchParameters.edgeLabels,
406	      edgeMode: EdgeMode.ALL,
407	      graphLayout: store.getState().graph.layout,
408	      namespaceLayout: store.getState().graph.namespaceLayout,
409	      graphType: graphType,
410	      node: this.props.dataSource.fetchParameters.node!,
411	      refreshInterval: store.getState().userSettings.refreshInterval,
412	      showIdleEdges: this.props.dataSource.fetchParameters.showIdleEdges,
413	      showIdleNodes: this.props.dataSource.fetchParameters.showIdleNodes,
414	      showOperationNodes: this.props.dataSource.fetchParameters.showOperationNodes,
415	      showServiceNodes: true,
416	      showVirtualServices: true,
417	      showWaypoints: this.props.dataSource.fetchParameters.showWaypoints,
418	      trafficRates: this.props.dataSource.fetchParameters.trafficRates
419	    };
420	
421	    // To ensure updated components get the updated URL, update the URL first and then the state
422	    if (isParentKiosk(this.props.kiosk)) {
423	      kioskContextMenuAction(makeNodeGraphUrlFromParams(urlParams));
424	    } else {
425	      router.navigate(makeNodeGraphUrlFromParams(urlParams));
426	    }
427	  };
428	
429	  private toggleTimeOptionsVisibility = (): void => {
430	    this.setState(prevState => ({ isTimeOptionsOpen: !prevState.isTimeOptionsOpen }));
431	  };
432	}
433	
434	const mapStateToProps = (state: KialiAppState): { kiosk: string } => ({
435	  kiosk: state.globalState.kiosk
436	});
437	
438	const mapDispatchToProps = (dispatch: KialiDispatch): ReduxDispatchProps => ({
439	  setEdgeMode: bindActionCreators(GraphActions.setEdgeMode, dispatch),
440	  setLayout: bindActionCreators(GraphActions.setLayout, dispatch),
441	  setUpdateTime: (val: TimeInMilliseconds) => dispatch(GraphActions.setUpdateTime(val)),
442	  updateSummary: (summaryData: SummaryData) => dispatch(GraphActions.updateSummary(summaryData))
443	});
444	
445	export const MiniGraphCard = connect(mapStateToProps, mapDispatchToProps)(MiniGraphCardComponent);

