138	      (this.props.workload && this.props.workload?.name !== this.props.dataSource.fetchParameters.node?.workload) ||
139	      (this.props.serviceDetails &&
140	        this.props.serviceDetails?.service.name !== this.props.dataSource.fetchParameters.node?.service)
141	        ? true
142	        : this.props.dataSource.isLoading;
143	
144	    const rangeEnd: TimeInMilliseconds = this.props.dataSource.graphTimestamp * 1000;
145	    const rangeStart: TimeInMilliseconds = rangeEnd - this.props.dataSource.graphDuration * 1000;
146	
147	    const intervalTitle =
148	      rangeEnd > 0 ? toRangeString(rangeStart, rangeEnd, { second: '2-digit' }, { second: '2-digit' }) : 'Loading';
149	
150	    return (
151	      <>
152	        <Card style={{ height: '100%' }} id={'MiniGraphCard'} data-test="mini-graph">
153	          <CardHeader
154	            actions={{
155	              actions: (
156	                <>
157	                  <KioskElement>
158	                    <ToolbarItem>
159	                      <TimeDurationIndicator onClick={this.toggleTimeOptionsVisibility} isDuration={true} />
160	                    </ToolbarItem>
161	                  </KioskElement>
162	                  <Dropdown
163	                    toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
164	                      <MenuToggle
165	                        id="minigraph-toggle"
166	                        ref={toggleRef}
167	                        className={kebabToggleStyle}
168	                        aria-label="Actions"
169	                        variant="plain"
170	                        onClick={() => this.onGraphActionsToggle(!this.state.isKebabOpen)}
171	                        isExpanded={this.state.isKebabOpen}
172	                      >
173	                        <KialiIcon.KebabToggle />
174	                      </MenuToggle>
175	                    )}
176	                    isOpen={this.state.isKebabOpen}
177	                    onOpenChange={(isOpen: boolean) => this.onGraphActionsToggle(isOpen)}
178	                    popperProps={{ position: 'right' }}
179	                  >
180	                    <DropdownList>{graphCardActions}</DropdownList>
181	                  </Dropdown>
182	                </>
183	              ),
184	              hasNoOffset: false,
185	              className: undefined
186	            }}
187	          >
188	            <CardTitle style={{ float: 'left' }}>{intervalTitle}</CardTitle>
189	          </CardHeader>
190	
191	          <CardBody>
192	            <div id="pft-graph" style={{ height: '100%' }}>
193	              <EmptyGraphLayout
194	                elements={this.state.graphData}
195	                isLoading={isLoading}
196	                isError={this.props.dataSource.isError}
197	                isMiniGraph={true}
198	                loaded={true}
199	              >
200	                <Graph
201	                  edgeLabels={this.props.dataSource.fetchParameters.edgeLabels}
202	                  edgeMode={EdgeMode.ALL}
203	                  graphData={{
204	                    elements: this.state.graphData,
205	                    elementsChanged: true,
206	                    errorMessage: !!this.props.dataSource.errorMessage ? this.props.dataSource.errorMessage : undefined,
207	                    isError: this.props.dataSource.isError,
208	                    isLoading: isLoading,
209	                    loaded: true,
210	                    fetchParams: this.props.dataSource.fetchParameters,
211	                    timestamp: this.props.dataSource.graphTimestamp
212	                  }}
213	                  isMiniGraph={true}
214	                  layout={GraphLayout.Dagre}
215	                  onDeleteTrafficRouting={this.handleDeleteTrafficRouting}
216	                  onEdgeTap={this.handleEdgeTap}
217	                  onLaunchWizard={this.handleLaunchWizard}
218	                  onNodeTap={this.handleNodeTap}
219	                  onReady={this.handleReady}
220	                  rankBy={[]}
221	                  setEdgeMode={this.props.setEdgeMode}
222	                  setLayout={this.props.setLayout}
223	                  setRankResult={() => {}}
224	                  setUpdateTime={this.props.setUpdateTime}
225	                  updateSummary={this.props.updateSummary}
226	                  showLegend={false}
227	                  showRank={false}
228	                  showOutOfMesh={true}
