236	        </Card>
237	
238	        <TimeDurationModal
239	          customDuration={false}
240	          isOpen={this.state.isTimeOptionsOpen}
241	          onConfirm={this.toggleTimeOptionsVisibility}
242	          onCancel={this.toggleTimeOptionsVisibility}
